mapper.select:
select a.`id`, a.team_id, t.name as team_name,`activity_id`, s.name as activity_name, u.name as user_name, `user_id`
from activity_user a
             left join team t ON t.id = a.team_id
             left join activity s ON a.activity_id = s.id
             left join user u on a.user_id = u.id


        and a.id = #{id}


        and a.team_id = #{teamId}


        and activity_id = #{activityId}


        and user_id = #{userId}

select a.`id`, a.team_id, t.name as team_name,`activity_id`, s.name as activity_name, u.name as user_name, `user_id`
from activity_user a
             left join team t ON t.id = a.team_id
             left join activity s ON a.activity_id = s.id
             left join user u on a.user_id = u.id


        and a.id = #{id}


        and a.team_id = #{teamId}


        and activity_id = #{activityId}


        and user_id = #{userId}
